var app = builder.Build();
app.MapGet("/", () => "Hello");
app.Run();

arguments.new_str:
using Microsoft.ML;
using Microsoft.Extensions.ML;
using ChurnPredictor;

var builder = WebApplication.CreateBuilder(args);

var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");

// Load data and split into train/test sets
var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(
    dataPath, hasHeader: true, separatorChar: ',');

// Map "Yes"/"No" string to boolean label
var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2, seed: 42);

// Build the ML pipeline
var pipeline = mlContext.Transforms.Categorical
        .OneHotEncoding("RegionEncoded", nameof(CustomerData.Region))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age),
        nameof(CustomerData.Income),
        "RegionEncoded",
        nameof(CustomerData.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers
        .FastTree(numberOfLeaves: 20, numberOfTrees: 100, minimumExampleCountPerLeaf: 1));

// Train
var model = pipeline.Fit(split.TrainSet);

// Evaluate on test set
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions);

Console.WriteLine("=== Churn Model Metrics ===");
Console.WriteLine($"  AUC:      {metrics.AreaUnderRocCurve:F4}");
Console.WriteLine($"  Accuracy: {metrics.Accuracy:F4}");
Console.WriteLine($"  F1 Score: {metrics.F1Score:F4}");

// Save and register the model for prediction pooling
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "ChurnModel.zip");
mlContext.Model.Save(model, dataView.Schema, modelPath);

builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with Age, Income, Region, PurchaseHistory");

app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, CustomerData customer) =>
{
    var prediction = pool.Predict(customer);
    return Results.Ok(new
    {
        WillChurn = prediction.Churned,
        prediction.Probability,
        prediction.Score,
    });
});

app.Run();

