using Microsoft.ML;
using Microsoft.Extensions.ML;
using ChurnPredictor;

var builder = WebApplication.CreateBuilder(args);

var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");

// Load CSV and convert "Yes"/"No" to boolean Label
var rawData = mlContext.Data.LoadFromTextFile<CustomerData>(
    dataPath, hasHeader: true, separatorChar: ',');

var customers = mlContext.Data.CreateEnumerable<CustomerData>(rawData, reuseRowObject: false)
    .Select(c => new CustomerFeatures
    {
        Age = c.Age,
        Income = c.Income,
        Region = c.Region,
        PurchaseHistory = c.PurchaseHistory,
        Label = string.Equals(c.Churned, "Yes", StringComparison.OrdinalIgnoreCase),
    })
    .ToList();

var dataView = mlContext.Data.LoadFromEnumerable(customers);
var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2, seed: 42);

// Build the ML pipeline
var pipeline = mlContext.Transforms.Categorical
        .OneHotEncoding("RegionEncoded", nameof(CustomerFeatures.Region))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerFeatures.Age),
        nameof(CustomerFeatures.Income),
        "RegionEncoded",
        nameof(CustomerFeatures.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers
        .FastTree(numberOfLeaves: 20, numberOfTrees: 100, minimumExampleCountPerLeaf: 1));

