 // Load CSV and convert "Yes"/"No" to boolean Label
 var rawData = mlContext.Data.LoadFromTextFile<CustomerData>(
     dataPath, hasHeader: true, separatorChar: ',');

 var customers = mlContext.Data.CreateEnumerable<CustomerData>(rawData, reuseRowObject: false)
     .Select(c => new CustomerFeatures
     {
         Age = c.Age,
         Income = c.Income,
         Region = c.Region,
         PurchaseHistory = c.PurchaseHistory,
         Label = string.Equals(c.Churned, "Yes", StringComparison.OrdinalIgnoreCase),
     })
     .ToList();

 var dataView = mlContext.Data.LoadFromEnumerable(customers);
 var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2, seed: 42);

