 app.MapPost("/predict", (PredictionEnginePool<CustomerFeatures, ChurnPrediction> pool, CustomerFeatures customer) =>
 {
     var prediction = pool.Predict(customer);
     return Results.Ok(new
     {
         WillChurn = prediction.Churned,
         prediction.Probability,
         prediction.Score,
     });
 });

 app.Run();

