     .Select(c => new CustomerFeatures
     {
         Age = c.Age,
         Income = c.Income,
         Region = c.Region,
         PurchaseHistory = c.PurchaseHistory,
         Label = string.Equals(c.Churned, "Yes", StringComparison.OrdinalIgnoreCase),
     })
     .ToList();

 var dataView = mlContext.Data.LoadFromEnumerable(customers);

 // Use train/test split when dataset is large enough; otherwise train and evaluate on full data
 const int minRowsForSplit = 20;
 IDataView trainData, testData;

