     Console.WriteLine("Add more data for a proper train/test split (≥20 rows recommended).");
     trainData = dataView;
     testData = dataView;
 }

 // Build the ML pipeline
 var pipeline = mlContext.Transforms.Categorical
         .OneHotEncoding("RegionEncoded", nameof(CustomerFeatures.Region))
     .Append(mlContext.Transforms.Concatenate("Features",
