 // Save and register the model for prediction pooling
 var modelPath = Path.Combine(builder.Environment.ContentRootPath, "ChurnModel.zip");
 mlContext.Model.Save(model, dataView.Schema, modelPath);

 builder.Services.AddPredictionEnginePool<CustomerFeatures, ChurnPrediction>()
